import { useState } from "react";
import axios from "axios";

function Register() {
  const [data, setData] = useState({
    name: "",
    email: "",
    password: "",
    role: "patient",
    specialization: "",
    qualification: "",
    timings: ""
  });

  const handleRegister = async () => {
    try {
      if (!data.name || !data.email || !data.password) {
        return alert("Please fill required fields");
      }

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        data
      );

      alert(res.data.message);
      window.location.href = "/";

    } catch (err) {
      alert(err.response?.data?.message || "Register Error");
    }
  };

  return (
    <div className="container">

      <div className="card">

        {/* 🏥 Hospital Branding */}
        <h1>🏥 LifeCare Hospital</h1>
        <p>Quality Healthcare for Everyone</p>

        <h2>Register</h2>

        <input
          placeholder="Name"
          onChange={e => setData({ ...data, name: e.target.value })}
        />

        <input
          placeholder="Email"
          onChange={e => setData({ ...data, email: e.target.value })}
        />

        <input
          type="password"
          placeholder="Password"
          onChange={e => setData({ ...data, password: e.target.value })}
        />

        {/* Role Selection */}
        <select
          onChange={e => setData({ ...data, role: e.target.value })}
        >
          <option value="patient">Patient</option>
          <option value="doctor">Doctor</option>
        </select>

        {/* Doctor Fields */}
        {data.role === "doctor" && (
          <>
            <input
              placeholder="Specialization"
              onChange={e =>
                setData({ ...data, specialization: e.target.value })
              }
            />

            <input
              placeholder="Qualification"
              onChange={e =>
                setData({ ...data, qualification: e.target.value })
              }
            />

            <input
              placeholder="Timings (e.g. 10AM - 4PM)"
              onChange={e =>
                setData({ ...data, timings: e.target.value })
              }
            />
          </>
        )}

        <button onClick={handleRegister}>
          Register
        </button>

        <p
          className="link"
          onClick={() => window.location.href = "/"}
        >
          Already have an account? Login
        </p>

      </div>

    </div>
  );
}

export default Register;
